import{_ as t,o as i,c as g,ag as a}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Quản lý Người dùng","description":"","frontmatter":{},"headers":[],"relativePath":"admin-users.md","filePath":"admin-users.md"}'),o={name:"admin-users.md"};function r(h,n,l,u,s,c){return i(),g("div",null,[...n[0]||(n[0]=[a('<h1 id="quan-ly-nguoi-dung" tabindex="-1">Quản lý Người dùng <a class="header-anchor" href="#quan-ly-nguoi-dung" aria-label="Permalink to &quot;Quản lý Người dùng&quot;">​</a></h1><blockquote><p>Quản lý tài khoản, vai trò và quyền trên nền tảng.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Quản lý người dùng cho phép quản trị viên tạo, chỉnh sửa, nhập và xóa tài khoản, cũng như chỉ định vai trò và quyền truy cập phù hợp.</p><blockquote><p>Chỉ dành cho Quản trị viên có quyền Quản lý Người dùng.</p></blockquote><h2 id="cach-truy-cap" tabindex="-1">Cách Truy cập <a class="header-anchor" href="#cach-truy-cap" aria-label="Permalink to &quot;Cách Truy cập&quot;">​</a></h2><ol><li>Nhấp vào <strong>Biểu tượng Cài đặt</strong> (Bánh răng) ở góc trên bên phải.</li><li>Chọn &quot;Quản lý Người dùng&quot; trong bảng điều khiển.</li></ol><hr><h2 id="cau-truc-trang" tabindex="-1">Cấu trúc Trang <a class="header-anchor" href="#cau-truc-trang" aria-label="Permalink to &quot;Cấu trúc Trang&quot;">​</a></h2><ul><li><strong>Thanh Tiêu đề</strong>: Bao gồm nút Lọc, Thêm Người dùng, và menu Hành động khác.</li><li><strong>Nhãn Lọc</strong>: Các bộ lọc đang được áp dụng.</li><li><strong>Bảng Người dùng</strong>: Danh sách tất cả người dùng.</li><li><strong>Phân trang</strong>: Thanh điều hướng trang.</li></ul><hr><h2 id="loc-nguoi-dung" tabindex="-1">Lọc Người dùng <a class="header-anchor" href="#loc-nguoi-dung" aria-label="Permalink to &quot;Lọc Người dùng&quot;">​</a></h2><p>Nhấp vào <strong>&quot;Bộ lọc&quot;</strong> để mở bảng lọc:</p><ul><li><strong>Công ty</strong>: Lọc theo công ty.</li><li><strong>Phòng ban</strong>: Lọc theo phòng ban (Yêu cầu chọn Công ty trước).</li><li><strong>Quyền</strong>: Quản trị viên / Người dùng / Siêu người dùng / Giám sát.</li><li><strong>Email</strong>: Tìm kiếm văn bản.</li><li><strong>Tên</strong>: Tìm kiếm văn bản.</li><li><strong>Trạng thái</strong>: Hoạt động / Vô hiệu hóa.</li></ul><hr><h2 id="them-nguoi-dung" tabindex="-1">Thêm Người dùng <a class="header-anchor" href="#them-nguoi-dung" aria-label="Permalink to &quot;Thêm Người dùng&quot;">​</a></h2><p>Nhấp vào <strong>&quot;Thêm Người dùng&quot;</strong> để mở biểu mẫu.</p><ul><li><strong>Tên</strong>: Tên hiển thị (Bắt buộc nếu có Email).</li><li><strong>Email</strong>: Tên đăng nhập (Bắt buộc hoặc Mã NV).</li><li><strong>Mã NV</strong>: Mã số nhân viên.</li><li><strong>Công ty</strong>: Chọn công ty (Bắt buộc).</li><li><strong>Phòng ban</strong>: Chọn phòng ban.</li><li><strong>Quyền</strong>: Chọn vai trò.</li><li><strong>Trạng thái</strong>: Bật / Tắt.</li></ul><h3 id="mo-ta-vai-tro" tabindex="-1">Mô tả Vai trò <a class="header-anchor" href="#mo-ta-vai-tro" aria-label="Permalink to &quot;Mô tả Vai trò&quot;">​</a></h3><ul><li><strong>Quản trị viên</strong>: Quyền truy cập đầy đủ vào tất cả chức năng quản lý.</li><li><strong>Siêu người dùng</strong>: Quyền nâng cao nhưng giới hạn một số chức năng quản lý.</li><li><strong>Giám sát</strong>: Có thể xem dữ liệu thực hành của nhóm nhưng không thể sửa cài đặt.</li><li><strong>Người dùng</strong>: Chỉ có thể sử dụng các chức năng thực hành và đánh giá cơ bản.</li></ul><hr><h2 id="tinh-nang-khac" tabindex="-1">Tính năng Khác <a class="header-anchor" href="#tinh-nang-khac" aria-label="Permalink to &quot;Tính năng Khác&quot;">​</a></h2><ul><li><strong>Chỉnh sửa Người dùng</strong>: Nhấp vào &quot;Chỉnh sửa&quot; trong bảng để sửa thông tin.</li><li><strong>Xóa Người dùng</strong>: Nhấp vào &quot;Xóa&quot;. Tài khoản sẽ bị vô hiệu hóa (xóa mềm).</li><li><strong>Nhập Hàng loạt</strong>: Sử dụng tệp CSV mẫu để thêm nhiều người dùng cùng lúc.</li><li><strong>Xóa Hàng loạt</strong>: Chọn nhiều người dùng và xóa cùng lúc.</li></ul>',23)])])}const m=t(o,[["render",r]]);export{d as __pageData,m as default};
